fn render_doctor_status_markdown(bundle_root: &Path, status: &serde_json::Value) -> String {
    let mut markdown = String::new();
    markdown.push_str("# memd doctor\n\n");
    markdown.push_str(&format!("- bundle: `{}`\n", bundle_root.display()));
    markdown.push_str(&format!(
        "- ready: `{}`\n",
        status
            .get("setup_ready")
            .and_then(|value| value.as_bool())
            .unwrap_or(false)
    ));
    if let Some(missing) = status.get("missing").and_then(|value| value.as_array()) {
        if !missing.is_empty() {
            markdown.push_str("\n## Missing\n");
            for item in missing {
                markdown.push_str(&format!("- {}\n", item.as_str().unwrap_or("unknown")));
            }
        }
    }
    if let Some(evolution) = status
        .get("evolution")
        .and_then(|value| if value.is_null() { None } else { Some(value) })
    {
        markdown.push_str("\n## Evolution\n");
        markdown.push_str(&format!(
            "- proposal state: `{}`\n",
            evolution
                .get("proposal_state")
                .and_then(|value| value.as_str())
                .unwrap_or("none")
        ));
        markdown.push_str(&format!(
            "- scope: `{}` / `{}`\n",
            evolution
                .get("scope_class")
                .and_then(|value| value.as_str())
                .unwrap_or("none"),
            evolution
                .get("scope_gate")
                .and_then(|value| value.as_str())
                .unwrap_or("none")
        ));
        markdown.push_str(&format!(
            "- authority: `{}`\n",
            evolution
                .get("authority_tier")
                .and_then(|value| value.as_str())
                .unwrap_or("none")
        ));
        markdown.push_str(&format!(
            "- queues: merge=`{}` durability=`{}`\n",
            evolution
                .get("merge_status")
                .and_then(|value| value.as_str())
                .unwrap_or("none"),
            evolution
                .get("durability_status")
                .and_then(|value| value.as_str())
                .unwrap_or("none")
        ));
        markdown.push_str(&format!(
            "- branch: `{}`\n",
            evolution
                .get("branch")
                .and_then(|value| value.as_str())
                .unwrap_or("none")
        ));
    }
    markdown
}

