fn collect_project_bootstrap_sources(project_root: &Path) -> Vec<PathBuf> {
    let mut sources = Vec::new();
    let candidates = [
        "CLAUDE.md",
        ".claude/CLAUDE.md",
        ".agents/CLAUDE.md",
        "DESIGN.md",
        ".claude/DESIGN.md",
        ".agents/DESIGN.md",
        "AGENTS.md",
        "TEAMS.md",
        "MEMORY.md",
        "SOUL.md",
        "USER.md",
        "IDENTITY.md",
        "TOOLS.md",
        "BOOTSTRAP.md",
        "HEARTBEAT.md",
        "README.md",
        "CONTRIBUTING.md",
        "ROADMAP.md",
        "docs/setup.md",
        "docs/config.md",
        "docs/infra-facts.md",
        "docs/release-process.md",
        "docs/maintainer-workflow.md",
        ".planning/STATE.md",
        ".planning/PROJECT.md",
        ".planning/ROADMAP.md",
        ".planning/codebase/ARCHITECTURE.md",
        ".planning/codebase/STRUCTURE.md",
    ];

    for candidate in candidates {
        let path = project_root.join(candidate);
        if path.is_file() {
            sources.push(path);
        }
    }

    let claude_project_memory = claude_project_memory_path(project_root);
    if claude_project_memory.is_file() {
        sources.push(claude_project_memory);
    }

    sources.extend(collect_memory_dir_sources(project_root));
    sources.extend(collect_design_dir_sources(project_root));

    sources
}

