#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
enum RetrievalTier {
    Hot,
    Working,
    Rehydration,
    Evidence,
    RawFallback,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct TruthRecordSummary {
    lane: String,
    truth: String,
    freshness: String,
    retrieval_tier: RetrievalTier,
    confidence: f32,
    provenance: String,
    preview: String,
}

